1560   // other operand.
1561   assert((NarrowUse->getOperand(0) == NarrowDef ||
1562           NarrowUse->getOperand(1) == NarrowDef) &&
1563          "bad DU");
1564 
1565   const OverflowingBinaryOperator *OBO =
1566     cast<OverflowingBinaryOperator>(NarrowUse);
1567   ExtendKind ExtKind = getExtendKind(NarrowDef);
1568   bool CanSignExtend = ExtKind == ExtendKind::Sign && OBO->hasNoSignedWrap();
1569   bool CanZeroExtend = ExtKind == ExtendKind::Zero && OBO->hasNoUnsignedWrap();
1570   auto AnotherOpExtKind = ExtKind;
1571 
1572   // Check that all uses are either:
1573   // - narrow def (in case of we are widening the IV increment);
1574   // - single-input LCSSA Phis;
1575   // - comparison of the chosen type;
1576   // - extend of the chosen type (raison d'etre).
1577   SmallVector<Instruction *, 4> ExtUsers;
1578   SmallVector<PHINode *, 4> LCSSAPhiUsers;
1579   SmallVector<ICmpInst *, 4> ICmpUsers;
1580   for (Use &U : NarrowUse->uses()) {
1581     Instruction *User = cast<Instruction>(U.getUser());
1582     if (User == NarrowDef)
1583       continue;
1584     if (!L->contains(User)) {
1585       auto *LCSSAPhi = cast<PHINode>(User);
1586       // Make sure there is only 1 input, so that we don't have to split
1587       // critical edges.
1588       if (LCSSAPhi->getNumOperands() != 1)
1589         return false;
1590       LCSSAPhiUsers.push_back(LCSSAPhi);
1591       continue;
1592     }
1593     if (auto *ICmp = dyn_cast<ICmpInst>(User)) {
1594       auto Pred = ICmp->getPredicate();
1595       // We have 3 types of predicates: signed, unsigned and equality
1596       // predicates. For equality, it's legal to widen icmp for either sign and
1597       // zero extend. For sign extend, we can also do so for signed predicates,
1598       // likeweise for zero extend we can widen icmp for unsigned predicates.
1599       if (ExtKind == ExtendKind::Zero && ICmpInst::isSigned(Pred))
1600         return false;
1601       if (ExtKind == ExtendKind::Sign && ICmpInst::isUnsigned(Pred))
1602         return false;
1603       ICmpUsers.push_back(ICmp);
1604       continue;
1605     }
1606     if (ExtKind == ExtendKind::Sign)
1607       User = dyn_cast<SExtInst>(User);
1608     else
1609       User = dyn_cast<ZExtInst>(User);
1610     if (!User || User->getType() != WideType)
1611       return false;
1612     ExtUsers.push_back(User);
1613   }
1614   if (ExtUsers.empty()) {
1615     DeadInsts.emplace_back(NarrowUse);
1616     return true;
1617   }
1618 
1619   // We'll prove some facts that should be true in the context of ext users. If
1620   // there is no users, we are done now. If there are some, pick their common
1621   // dominator as context.
1622   const Instruction *CtxI = findCommonDominator(ExtUsers, *DT);
1623 
1624   if (!CanSignExtend && !CanZeroExtend) {
1625     // Because InstCombine turns 'sub nuw' to 'add' losing the no-wrap flag, we
1626     // will most likely not see it. Let's try to prove it.
1627     if (OpCode != Instruction::Add)
1628       return false;
1629     if (ExtKind != ExtendKind::Zero)
1630       return false;
1631     const SCEV *LHS = SE->getSCEV(OBO->getOperand(0));
1632     const SCEV *RHS = SE->getSCEV(OBO->getOperand(1));
1633     // TODO: Support case for NarrowDef = NarrowUse->getOperand(1).
1634     if (NarrowUse->getOperand(0) != NarrowDef)
1635       return false;
1636     if (!SE->isKnownNegative(RHS))
1637       return false;
1638     bool ProvedSubNUW = SE->isKnownPredicateAt(ICmpInst::ICMP_UGE, LHS,
1639                                                SE->getNegativeSCEV(RHS), CtxI);
1640     if (!ProvedSubNUW)
1641       return false;
1642     // In fact, our 'add' is 'sub nuw'. We will need to widen the 2nd operand as
1643     // neg(zext(neg(op))), which is basically sext(op).
1644     AnotherOpExtKind = ExtendKind::Sign;
1645   }
1646 
1647   // Verifying that Defining operand is an AddRec
1648   const SCEV *Op1 = SE->getSCEV(WideDef);
1649   const SCEVAddRecExpr *AddRecOp1 = dyn_cast<SCEVAddRecExpr>(Op1);
1650   if (!AddRecOp1 || AddRecOp1->getLoop() != L)
1651     return false;
1652 
1653   LLVM_DEBUG(dbgs() << "Cloning arithmetic IVUser: " << *NarrowUse << "\n");
1654 
1655   // Generating a widening use instruction.
1656   Value *LHS =
1657       (NarrowUse->getOperand(0) == NarrowDef)
1658           ? WideDef
1659           : createExtendInst(NarrowUse->getOperand(0), WideType,
1660                              AnotherOpExtKind == ExtendKind::Sign, NarrowUse);
1661   Value *RHS =
1662       (NarrowUse->getOperand(1) == NarrowDef)
1663           ? WideDef
1664           : createExtendInst(NarrowUse->getOperand(1), WideType,
1665                              AnotherOpExtKind == ExtendKind::Sign, NarrowUse);
1666 
1667   auto *NarrowBO = cast<BinaryOperator>(NarrowUse);
1668   auto *WideBO = BinaryOperator::Create(NarrowBO->getOpcode(), LHS, RHS,
1669                                         NarrowBO->getName());
1670   IRBuilder<> Builder(NarrowUse);
1671   Builder.Insert(WideBO);
1672   WideBO->copyIRFlags(NarrowBO);
1673   ExtendKindMap[NarrowUse] = ExtKind;
1674 
1675   for (Instruction *User : ExtUsers) {
1676     assert(User->getType() == WideType && "Checked before!");
1677     LLVM_DEBUG(dbgs() << "INDVARS: eliminating " << *User << " replaced by "
1678                       << *WideBO << "\n");
1679     ++NumElimExt;
1680     User->replaceAllUsesWith(WideBO);
1681     DeadInsts.emplace_back(User);
1682   }
1683 
1684   for (PHINode *User : LCSSAPhiUsers) {
1685     assert(User->getNumOperands() == 1 && "Checked before!");
1686     Builder.SetInsertPoint(User);
1687     auto *WidePN =
1688         Builder.CreatePHI(WideBO->getType(), 1, User->getName() + ".wide");
1689     BasicBlock *LoopExitingBlock = User->getParent()->getSinglePredecessor();
1690     assert(LoopExitingBlock && L->contains(LoopExitingBlock) &&
1691            "Not a LCSSA Phi?");
1692     WidePN->addIncoming(WideBO, LoopExitingBlock);
1693     Builder.SetInsertPoint(User->getParent(),
1694                            User->getParent()->getFirstInsertionPt());
1695     auto *TruncPN = Builder.CreateTrunc(WidePN, User->getType());
1696     User->replaceAllUsesWith(TruncPN);
1697     DeadInsts.emplace_back(User);
1698   }
1699 
1700   for (ICmpInst *User : ICmpUsers) {
1701     Builder.SetInsertPoint(User);
1702     auto ExtendedOp = [&](Value * V)->Value * {
1703       if (V == NarrowUse)
1704         return WideBO;
1705       if (ExtKind == ExtendKind::Zero)
1706         return Builder.CreateZExt(V, WideBO->getType());
1707       else
1708         return Builder.CreateSExt(V, WideBO->getType());
1709     };
1710     auto Pred = User->getPredicate();
1711     auto *LHS = ExtendedOp(User->getOperand(0));
1712     auto *RHS = ExtendedOp(User->getOperand(1));
1713     auto *WideCmp =
1714         Builder.CreateICmp(Pred, LHS, RHS, User->getName() + ".wide");
1715     User->replaceAllUsesWith(WideCmp);
1716     DeadInsts.emplace_back(User);
------------------------------------------------------------
